```javascript
async function suggestAgent() {
  const input = document.getElementById('chatInput');
  const msg = input.value.trim();
  if (!msg) { toast('Type a message first', 'info'); return; }

  const { data, error } = await api('suggest-agent', {
    method: 'POST',
    body: { message: msg }
  });
  if (error) { toast(error, 'error'); return; }

  // Auto-select the suggested agent
  toast(`👼 Suggested: ${data.agentName}`, 'success');
  // Set the agent in the UI (find the agent selector and update it)
  selectAgent(data.agentId);
}
```

