// ── User Management (admin only) ──
function requireAdmin(req) {
  const token = (req.headers.authorization || '').replace('Bearer ', '')
  const auth = loadAuth()
  const session = auth.sessions[token]
  if (!session || session.role !== 'admin') return null
  return session
}

function requireAuth(req) {
  const token = (req.headers.authorization || '').replace('Bearer ', '')
  const auth = loadAuth()
  const session = auth.sessions[token]
  if (!session) return null
  return session
}

app.get('/api/admin/users', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const auth = loadAuth()
  const users = Object.entries(auth.users).map(([username, u]) => ({
    username, role: u.role, name: u.name || username
  }))
  const pending = Object.entries(auth.pending || {}).map(([username, p]) => ({
    username, requestedAt: p.requestedAt, status: p.status
  }))
  return { ok: true, users, pending }
})

app.post('/api/admin/users/approve', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { username, role } = req.body || {}
  if (!username) return { ok: false, error: 'Username required' }
  const auth = loadAuth()
  if (!auth.pending || !auth.pending[username]) return { ok: false, error: 'No pending registration for this user' }
  const p = auth.pending[username]
  auth.users[username] = { password: p.password, role: role || 'user', name: username }
  delete auth.pending[username]
  saveAuth(auth)
  trackEvent('auth_user_approved', { username, role: role || 'viewer' })
  return { ok: true }
})

app.post('/api/admin/users/reject', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { username } = req.body || {}
  if (!username) return { ok: false, error: 'Username required' }
  const auth = loadAuth()
  if (auth.pending && auth.pending[username]) { delete auth.pending[username]; saveAuth(auth) }
  trackEvent('auth_user_rejected', { username })
  return { ok: true }
})

app.put('/api/admin/users/:username/role', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { username } = req.params
  const { role } = req.body || {}
  if (!role || !['admin', 'user'].includes(role)) return { ok: false, error: 'Role must be admin or user' }
  const auth = loadAuth()
  if (!auth.users[username]) return { ok: false, error: 'User not found' }
  auth.users[username].role = role
  saveAuth(auth)
  trackEvent('auth_role_change', { username, role })
  return { ok: true }
})

app.delete('/api/admin/users/:username', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { username } = req.params
  const auth = loadAuth()
  if (!auth.users[username]) return { ok: false, error: 'User not found' }
  if (username === 'lucy') return { ok: false, error: 'Cannot delete core admin account' }
  delete auth.users[username]
  // Remove their sessions too
  for (const [token, s] of Object.entries(auth.sessions || {})) {
    if (s.username === username) delete auth.sessions[token]
  }
  saveAuth(auth)
  trackEvent('auth_user_deleted', { username })
  return { ok: true }
})

