const VAULT_ROOT = join(HOME, 'livesync-bridge', 'vault')

// List vault tree
app.get('/api/vault/tree', async () => {
  function walkDir(dir, prefix = '') {
    const entries = readdirSync(dir, { withFileTypes: true })
    const items = []
    for (const e of entries) {
      if (e.name.startsWith('.')) continue
      const rel = prefix ? prefix + '/' + e.name : e.name
      if (e.isDirectory()) {
        items.push({ name: e.name, path: rel, type: 'folder', children: walkDir(join(dir, e.name), rel) })
      } else {
        const st = statSync(join(dir, e.name))
        items.push({ name: e.name, path: rel, type: 'file', size: st.size, modified: st.mtime.toISOString() })
      }
    }
    return items.sort((a, b) => {
      if (a.type !== b.type) return a.type === 'folder' ? -1 : 1
      return a.name.localeCompare(b.name)
    })
  }
  return { root: VAULT_ROOT, tree: walkDir(VAULT_ROOT) }
})

