// Track any event
function trackEvent(type, detail) {
  const events = loadEvents()
  events.push({ type, detail, ts: Date.now(), time: new Date().toISOString() })
  saveEvents(events)
}

// Track usage (called internally after each Bedrock call)
function trackUsage(agentId, modelId, inputTokens, outputTokens) {
  const analytics = loadAnalytics()
  const today = new Date().toISOString().slice(0, 10)
  if (!analytics.daily[today]) analytics.daily[today] = { requests: 0, inputTokens: 0, outputTokens: 0, agents: {}, models: {} }
  analytics.daily[today].requests++
  analytics.daily[today].inputTokens += inputTokens || 0
  analytics.daily[today].outputTokens += outputTokens || 0
  // Per-agent per-day
  if (!analytics.daily[today].agents[agentId]) analytics.daily[today].agents[agentId] = { requests: 0, inputTokens: 0, outputTokens: 0, model: modelId }
  analytics.daily[today].agents[agentId].requests++
  analytics.daily[today].agents[agentId].inputTokens += inputTokens || 0
  analytics.daily[today].agents[agentId].outputTokens += outputTokens || 0
  analytics.daily[today].agents[agentId].model = modelId
  // Per-model per-day
  const modelLabel = modelId.split('.').pop()
  if (!analytics.daily[today].models) analytics.daily[today].models = {}
  if (!analytics.daily[today].models[modelLabel]) analytics.daily[today].models[modelLabel] = { requests: 0, inputTokens: 0, outputTokens: 0 }
  analytics.daily[today].models[modelLabel].requests++
  analytics.daily[today].models[modelLabel].inputTokens += inputTokens || 0
  analytics.daily[today].models[modelLabel].outputTokens += outputTokens || 0
  // Totals
  if (!analytics.agentUsage[agentId]) analytics.agentUsage[agentId] = 0
  analytics.agentUsage[agentId]++
  if (!analytics.modelUsage[modelId]) analytics.modelUsage[modelId] = 0
  analytics.modelUsage[modelId]++
  // Estimated cost
  const COST = {
    'us.anthropic.claude-3-haiku-20240307-v1:0': [0.25, 1.25],
    'us.anthropic.claude-3-5-haiku-20241022-v1:0': [0.80, 4.00],
    'us.anthropic.claude-sonnet-4-6': [3.00, 15.00],
    'us.anthropic.claude-sonnet-4-20250514-v1:0': [3.00, 15.00],
    'us.anthropic.claude-opus-4-6-v1': [15.00, 75.00]
  }
  const pricing = COST[modelId] || [3, 15]
  const cost = ((inputTokens || 0) / 1e6) * pricing[0] + ((outputTokens || 0) / 1e6) * pricing[1]
  analytics.totalCost = (analytics.totalCost || 0) + cost
  if (!analytics.daily[today].cost) analytics.daily[today].cost = 0
  analytics.daily[today].cost += cost
  // Keep only last 90 days
  const cutoff = new Date(Date.now() - 90 * 86400000).toISOString().slice(0, 10)
  for (const d of Object.keys(analytics.daily)) { if (d < cutoff) delete analytics.daily[d] }
  saveAnalytics(analytics)
  // Also track as event
  trackEvent('bedrock_call', { agentId, model: modelLabel, inputTokens, outputTokens, cost: +cost.toFixed(6) })
}

