async function sendWhatsApp(phone, message) {
  const gwToken = process.env.OPENCLAW_GATEWAY_TOKEN || ''
  const resp = await fetch('http://127.0.0.1:18789/api/message', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + gwToken },
    body: JSON.stringify({ action: 'send', target: phone, message })
  })
  if (!resp.ok) throw new Error('Gateway send failed: ' + resp.status)
