// POST — add new contact to both openclaw.json allowFrom AND wa-contacts.json
app.post('/wa-allowlist', async (req) => {
  try {
    let { number, label, role, access } = req.body || {}
    if (!number || typeof number !== 'string') return { ok: false, error: 'number required' }
    number = formatNumber(number)
    const cfg = readOpenClawConfig()
    if (!cfg.channels) cfg.channels = {}
    if (!cfg.channels.whatsapp) cfg.channels.whatsapp = {}
    if (!Array.isArray(cfg.channels.whatsapp.allowFrom)) cfg.channels.whatsapp.allowFrom = []
    if (cfg.channels.whatsapp.allowFrom.includes(number)) {
      return { ok: false, error: 'Number already in allowlist' }
    }
    cfg.channels.whatsapp.allowFrom.push(number)
    writeOpenClawConfig(cfg)
    // Save metadata
    const meta = readWAContacts()
    meta[number] = { label: label || '', role: role || 'friend', access: access || 'basic' }
    writeWAContacts(meta)
    restartGateway()
    trackEvent('wa_allowlist_add', { number, label, role, access })
    // Return merged contacts
    const contacts = cfg.channels.whatsapp.allowFrom.map(n => ({
      number: n, label: meta[n]?.label || '', role: meta[n]?.role || 'friend', access: meta[n]?.access || 'basic'
    }))
    return { ok: true, contacts }
  } catch (e) {
    return { ok: false, error: e.message }
  }
})

