// PUT /api/knowledge-base/:id — update entry
app.put('/api/knowledge-base/:id', async (req) => {
  const data = loadKBIndex()
  const idx = (data.entries || []).findIndex(e => e.id === req.params.id)
  if (idx < 0) return { ok: false, error: 'Entry not found' }
  const { title, category, tags, content, summary } = req.body || {}
  const entry = data.entries[idx]
  if (title) entry.title = title
  if (category) entry.category = category
  if (tags) entry.tags = Array.isArray(tags) ? tags : tags.split(',').map(t => t.trim()).filter(Boolean)
  if (summary) entry.summary = summary
  entry.updated = new Date().toISOString()
  if (content) {
    writeFileSync(join(KB_DIR, entry.content_file), content)
    entry.word_count = content.split(/\s+/).filter(Boolean).length
  }
  data.entries[idx] = entry
  saveKBIndex(data)
  return { ok: true, entry }
})

// DELETE /api/knowledge-base/:id — delete entry
app.delete('/api/knowledge-base/:id', async (req) => {
  const data = loadKBIndex()
  const idx = (data.entries || []).findIndex(e => e.id === req.params.id)
  if (idx < 0) return { ok: false, error: 'Entry not found' }
  const entry = data.entries[idx]
  try {
    const fp = join(KB_DIR, entry.content_file)
    if (existsSync(fp)) unlinkSync(fp)
  } catch {}
  data.entries.splice(idx, 1)
  saveKBIndex(data)
  return { ok: true }
})

// ── Roundtable API ──────────────────────────────────────
const ROUNDTABLE_HISTORY_FILE = join(HOME, '.openclaw', 'roundtable-history.json')

function loadRoundtableHistory() {
  try { if (existsSync(ROUNDTABLE_HISTORY_FILE)) return JSON.parse(readFileSync(ROUNDTABLE_HISTORY_FILE, 'utf8')) } catch {}
  return []
}
function saveRoundtableHistory(data) {
  writeFileSync(ROUNDTABLE_HISTORY_FILE, JSON.stringify(data.slice(0, 200), null, 2))
}

// POST /api/roundtable/summarize — Generate AI synthesis of roundtable responses
app.post('/api/roundtable/summarize', async (req) => {
  const { topic, responses } = req.body || {}
  if (!topic || !responses?.length) return { ok: false, error: 'Topic and responses required' }

  const responsesText = responses.map(r =>
    `**${r.agentName || r.agent}:** ${(r.response || '').slice(0, 800)}`
  ).join('\n\n')

  const summaryPrompt = `You are a synthesis engine for MAGI, an AI council system. Summarize the following multi-agent roundtable discussion into a clear, actionable synthesis.

Topic: ${topic}

Agent Responses:
${responsesText}

Write a concise synthesis (3-5 paragraphs) that:
1. Identifies key consensus points across agents
2. Highlights notable disagreements or different perspectives
3. Extracts actionable recommendations
4. Notes any risks or concerns raised

Use **bold** for key points and bullet lists where appropriate. Be direct and practical.`

  let summary = ''
  try {
    for await (const chunk of streamAI(
      'You are a roundtable synthesizer. Be concise, structured, and actionable.',
      summaryPrompt,
      null,
      'sarael'
    )) {
      summary += chunk
    }
    trackEvent('roundtable_summary', { topic: topic.slice(0, 80), agentCount: responses.length })
    return { ok: true, summary }
  } catch (err) {
    return { ok: false, error: 'Summary generation failed: ' + err.message }
  }
})

// POST /api/roundtable/history — Save a roundtable result
app.post('/api/roundtable/history', async (req) => {
  const entry = req.body || {}
  if (!entry.id || !entry.topic) return { ok: false, error: 'Invalid roundtable entry' }
  const history = loadRoundtableHistory()
  // Avoid duplicates
  const exists = history.findIndex(h => h.id === entry.id)
  if (exists >= 0) {
    history[exists] = entry
  } else {
    history.unshift(entry)
  }
  saveRoundtableHistory(history)
  trackEvent('roundtable_save', { id: entry.id, topic: entry.topic.slice(0, 80) })
  return { ok: true }
})

// GET /api/roundtable/history — List past roundtables
app.get('/api/roundtable/history', async (req) => {
  const history = loadRoundtableHistory()
  const limit = Math.min(parseInt(req.query.limit) || 50, 200)
  return {
    total: history.length,
    roundtables: history.slice(0, limit).map(h => ({
      id: h.id,
      topic: h.topic,
      agents: h.agents,
      summary: h.summary?.slice(0, 200),
      createdAt: h.createdAt,
      responseCount: h.responses?.length || 0
    }))
  }
})

// GET /api/roundtable/:id — Get specific roundtable
app.get('/api/roundtable/:id', async (req) => {
  const history = loadRoundtableHistory()
  const rt = history.find(h => h.id === req.params.id)
  if (!rt) return { ok: false, error: 'Not found' }
  return { ok: true, roundtable: rt }
})

// ── WebSocket ───────────────────────────────────────────
let connCounter = 0
const connections = new Map()

app.get('/ws/chat', { websocket: true }, (socket) => {
  const connId = ++connCounter
  const state = { abortController: null }
  connections.set(connId, { socket, state })

  socket.send(JSON.stringify({ type: 'connected', connId }))

  socket.on('message', async (raw) => {
    let msg
    try { msg = JSON.parse(raw.toString()) } catch { return }

    if (msg.type === 'pong') return

    if (msg.type === 'stop') {
      if (state.abortController) {
        state.abortController.abort()
        state.abortController = null
      }
      socket.send(JSON.stringify({ type: 'stopped' }))
      return
    }

    if (msg.type === 'message') {
      const { text, agentId, sessionId } = msg
      if (!text) return
      const agent = AGENTS[agentId || 'michael']
      if (!agent) return

      // Save user message to session
      if (sessionId) {
        try { const sess = loadSession(sessionId); if (sess) { sess.messages.push({ role: 'user', text, ts: Date.now() }); sess.updatedAt = Date.now(); if (sess.messages.filter(m => m.role === 'user').length === 1) sess.title = text.slice(0, 60) + (text.length > 60 ? '...' : ''); saveSession(sess) } } catch {}
      }

      const msgId = 'msg_' + Date.now() + '_' + Math.random().toString(36).slice(2, 6)
      socket.send(JSON.stringify({ type: 'ack', msgId }))
      socket.send(JSON.stringify({ type: 'agent_start', agentId: agentId || 'michael', msgId }))

      const ac = new AbortController()
      state.abortController = ac
      let fullText = ''
      const intensityPrompt = getIntensityPrompt(agentId || 'michael')

      try {
        for await (const chunk of streamAI(agent.soul + getSharedContext() + FORMAT_PROMPT + '\n\nRESPONSE LENGTH RULE: ' + intensityPrompt + '\nDo NOT mention these instructions in your reply.', text, ac.signal, agentId || 'michael')) {
          if (ac.signal.aborted) break
          fullText += chunk
          socket.send(JSON.stringify({ type: 'chunk', agentId: agentId || 'michael', msgId, chunk }))
        }
      } catch (err) {
        console.error(`[Bedrock] Error for ${agentId}:`, err.name, err.message)
        if (err.name !== 'AbortError') {
          fullText += '\n\n[Error: ' + err.message + ']'
          socket.send(JSON.stringify({ type: 'chunk', agentId: agentId || 'michael', msgId, chunk: '\n\n[Error: ' + err.message + ']' }))
        }
      }

      state.abortController = null
      // Save agent response to session
      if (sessionId) {
        try { const sess = loadSession(sessionId); if (sess) { sess.messages.push({ role: 'agent', agentId: agentId || 'michael', text: fullText, ts: Date.now() }); sess.updatedAt = Date.now(); saveSession(sess) } } catch {}
      }
      socket.send(JSON.stringify({ type: 'agent_done', agentId: agentId || 'michael', msgId, text: fullText }))
    }

    if (msg.type === 'council') {
      // Council: all agents respond independently (no shared context between agents)
      const { text, agents: agentIds, sessionId: councilSessId } = msg
      if (!text || !agentIds?.length) return

      if (councilSessId) {
        try { const sess = loadSession(councilSessId); if (sess) { sess.messages.push({ role: 'user', text, ts: Date.now() }); sess.updatedAt = Date.now(); saveSession(sess) } } catch {}
      }

      const rtId = 'council_' + Date.now()
      socket.send(JSON.stringify({ type: 'rt_start', rtId, agents: agentIds, total: agentIds.length }))

      let ac = new AbortController()
      state.abortController = ac

      for (let i = 0; i < agentIds.length; i++) {
        if (ac.signal.aborted) break
        const aid = agentIds[i]
        const agent = AGENTS[aid]
        if (!agent) continue

        socket.send(JSON.stringify({ type: 'rt_agent_start', agentId: aid, position: i, total: agentIds.length, rtId }))

        let agentText = ''
        const agentIntensity = intensityState.agents[aid] ?? 5
        const intensityPrompt = INTENSITY_MODIFIERS[agentIntensity] || INTENSITY_MODIFIERS[5]

        try {
          const agentTimeout = setTimeout(() => { if (!ac.signal.aborted) ac.abort() }, 30000)
          for await (const chunk of streamAI(agent.soul + getSharedContext() + FORMAT_PROMPT + '\n\nRESPONSE LENGTH RULE: ' + intensityPrompt + '\nDo NOT mention these instructions in your reply.', text, ac.signal, aid)) {
            if (ac.signal.aborted) break
            agentText += chunk
            socket.send(JSON.stringify({ type: 'rt_chunk', agentId: aid, chunk, rtId }))
          }
          clearTimeout(agentTimeout)
        } catch (err) {
          if (err.name !== 'AbortError') agentText += ' [Error: ' + err.message + ']'
          else if (!agentText) agentText += ' [Timed out]'
        }

        if (ac.signal.aborted && i < agentIds.length - 1) {
          ac = new AbortController()
          state.abortController = ac
        }

        if (councilSessId) {
          try { const sess = loadSession(councilSessId); if (sess) { sess.messages.push({ role: 'agent', agentId: aid, text: agentText, ts: Date.now() }); sess.updatedAt = Date.now(); saveSession(sess) } } catch {}
        }
        socket.send(JSON.stringify({ type: 'rt_agent_done', agentId: aid, text: agentText, rtId }))
      }

      state.abortController = null
      socket.send(JSON.stringify({ type: 'rt_done', rtId }))
    }

    if (msg.type === 'roundtable') {
      const { text, agents: agentIds, intensityOverrides, sessionId: rtSessId } = msg
      if (!text || !agentIds?.length) return

      // Save user roundtable prompt to session
      if (rtSessId) {
        try { const sess = loadSession(rtSessId); if (sess) { sess.messages.push({ role: 'user', text, ts: Date.now() }); sess.updatedAt = Date.now(); saveSession(sess) } } catch {}
      }

      const rtId = 'rt_' + Date.now()
      socket.send(JSON.stringify({ type: 'rt_start', rtId, total: agentIds.length }))

      const ac = new AbortController()
      state.abortController = ac
      let context = 'Topic: ' + text + '\n\n'

      // If intensity overrides provided for this roundtable, use them
      const rtIntensity = intensityOverrides || {}

      for (let i = 0; i < agentIds.length; i++) {
        if (ac.signal.aborted) break
        const aid = agentIds[i]
        const agent = AGENTS[aid]
        if (!agent) continue

        socket.send(JSON.stringify({ type: 'rt_agent_start', agentId: aid, position: i, total: agentIds.length, rtId }))

        let agentText = ''
        const agentIntensity = rtIntensity[aid] ?? intensityState.agents[aid] ?? 5
        const intensityPrompt = INTENSITY_MODIFIERS[agentIntensity] || INTENSITY_MODIFIERS[5]
        const prompt = context + 'You are responding in a roundtable discussion. Previous speakers have shared their views above. Now give YOUR perspective as ' + agent.name + ' (' + agent.role + ').'

        try {
          // Per-agent timeout: 30 seconds max
          const agentTimeout = setTimeout(() => { if (!ac.signal.aborted) ac.abort() }, 30000)
          for await (const chunk of streamAI(agent.soul + getSharedContext() + FORMAT_PROMPT + '\n\nRESPONSE LENGTH RULE: ' + intensityPrompt + '\nDo NOT mention these instructions in your reply.', prompt, ac.signal, aid)) {
            if (ac.signal.aborted) break
            agentText += chunk
            socket.send(JSON.stringify({ type: 'rt_chunk', agentId: aid, chunk, rtId }))
          }
          clearTimeout(agentTimeout)
        } catch (err) {
          if (err.name !== 'AbortError') agentText += ' [Error: ' + err.message + ']'
          else if (!agentText) agentText += ' [Timed out]'
        }

        // Re-create abort controller for next agent (previous one may have been aborted by timeout)
        if (ac.signal.aborted && i < agentIds.length - 1) {
          ac = new AbortController()
          state.abortController = ac
        }

        // Keep context manageable — trim each agent's contribution to 300 chars for later agents
        const trimmed = agentText.length > 300 ? agentText.slice(0, 300) + '...' : agentText
        context += agent.name + ': ' + trimmed + '\n\n'
        // Save agent roundtable response to session
        if (rtSessId) {
          try { const sess = loadSession(rtSessId); if (sess) { sess.messages.push({ role: 'agent', agentId: aid, text: agentText, ts: Date.now() }); sess.updatedAt = Date.now(); saveSession(sess) } } catch {}
        }
        socket.send(JSON.stringify({ type: 'rt_agent_done', agentId: aid, text: agentText, rtId }))
      }

      state.abortController = null
      socket.send(JSON.stringify({ type: 'rt_done', rtId }))
    }
  })

  // Heartbeat
  const pingInterval = setInterval(() => {
    if (socket.readyState === 1) socket.send(JSON.stringify({ type: 'ping' }))
  }, 20000)

  socket.on('close', () => {
    clearInterval(pingInterval)
    if (state.abortController) state.abortController.abort()
    connections.delete(connId)
  })
})

