function handleWSMessage(msg){
  switch(msg.type){
    case'rt_start':break;
    case'rt_agent_start':activateCard(msg.agentId);break;
    case'rt_chunk':appendChunk(msg.agentId,msg.chunk);break;
    case'rt_agent_done':finalizeCard(msg.agentId,msg.text);break;
    case'rt_done':onRoundtableDone();break;
    // Also handle council mode (parallel)
    case'agent_start':activateCard(msg.agentId);break;
    case'chunk':appendChunk(msg.agentId,msg.chunk);break;
    case'agent_done':finalizeCard(msg.agentId,msg.text);checkAllDone();break;
  }
}

function checkAllDone(){
  if(!currentRoundtable)return;
  if(Object.keys(currentRoundtable.responses).length>=currentRoundtable.agents.length){
    onRoundtableDone();
  }
}


