function activateCard(agentId){
  const card=$('card-'+agentId);if(!card)return;
  card.classList.remove('waiting');card.classList.add('active-stream');
  const thinking=$('thinking-'+agentId);if(thinking)thinking.remove();
  const body=$('body-'+agentId);
  body.innerHTML='<div class="md-content" id="content-'+agentId+'"></div>';
}

function appendChunk(agentId,chunk){
  const content=$('content-'+agentId);if(!content)return;
  if(!content._rawText)content._rawText='';
  content._rawText+=chunk;
  // Use shared safe markdown renderer
  content.innerHTML=renderMarkdown(content._rawText);
}

function finalizeCard(agentId,text){
  const card=$('card-'+agentId);if(!card)return;
  card.classList.remove('active-stream');
  const content=$('content-'+agentId);
  if(content){content._rawText=text;content.innerHTML=renderMarkdown(text)}
  const footer=document.createElement('div');
  footer.className='agent-card-footer';
  footer.innerHTML=`<span class="ts">${new Date().toLocaleTimeString()}</span><span style="color:var(--color-accent)">✓ Done</span>`;
  card.appendChild(footer);
  if(currentRoundtable){
    currentRoundtable.responses[agentId]={text,timestamp:Date.now()};
    const done=Object.keys(currentRoundtable.responses).length;
    $('responseCount').textContent=`${done} / ${currentRoundtable.agents.length} responses`;
  }
}

async function onRoundtableDone(){
  isRunning=false;
  const btn=$('startBtn');
  btn.textContent='🗳️ Start Roundtable';btn.classList.remove('running');btn.disabled=false;
  if(!currentRoundtable)return;
  // Generate summary
  try{
    const {data,error}=await api('/api/roundtable/summarize',{method:'POST',body:{
      topic:currentRoundtable.topic,
      responses:Object.entries(currentRoundtable.responses).map(([agent,r])=>({agent,agentName:AGENT_META[agent]?.name||agent,response:r.text}))
    }});
    if(data?.ok&&data.summary){showSummary(data.summary);currentRoundtable.summary=data.summary}
    else{showSummary('*Summary generation failed. Review individual agent responses above.*')}
  }catch(e){console.error('Summary failed:',e);showSummary('*Summary generation failed. Review individual agent responses above.*')}
  saveToHistory(currentRoundtable);
}

function showSummary(text){
  $('summaryArea').innerHTML=`<div class="summary-card"><div class="summary-header"><span class="icon">✨</span><span class="label">AI Synthesis</span></div><div class="summary-body md-content">${renderMarkdown(text)}</div></div>`;
}

// ── History (with size guard) ──
function getHistory(){
  try{return JSON.parse(localStorage.getItem('magi-roundtable-history')||'[]')}catch{return[]}
}
function saveToHistory(rt){
  let history=getHistory();
  const entry={id:rt.id,topic:rt.topic,agents:rt.agents,
    responses:Object.entries(rt.responses).map(([agent,r])=>({agent,response:r.text,timestamp:r.timestamp})),
    summary:rt.summary||'',createdAt:rt.startedAt};
  history.unshift(entry);
  history=history.slice(0,50);
  // Size guard: prune oldest if > MAX_HISTORY_SIZE
  let json=JSON.stringify(history);
  while(json.length>MAX_HISTORY_SIZE&&history.length>1){
    history.pop();json=JSON.stringify(history);
  }
  try{localStorage.setItem('magi-roundtable-history',json)}catch(e){
    // Storage full: prune more aggressively
    history=history.slice(0,10);
    try{localStorage.setItem('magi-roundtable-history',JSON.stringify(history))}catch{}
  }
  // Also persist to backend
  api('/api/roundtable/history',{method:'POST',body:entry}).catch(()=>{});
  renderHistory();
}

function renderHistory(){
  const list=$('historyList');
  const history=getHistory();
  if(!history.length){list.innerHTML='<div class="history-empty">No roundtables yet</div>';return}
  list.innerHTML=history.map(h=>`
    <div class="history-item" onclick="window._loadHistory('${h.id}')">
      <div class="history-topic">${escHtml(h.topic)}</div>
      <div class="history-meta"><span>${h.agents?.length||0} agents</span><span>·</span><span>${timeAgo(h.createdAt)}</span></div>
    </div>`).join('');
}

function loadHistory(id){
  const history=getHistory();
  const h=history.find(x=>x.id===id);if(!h)return;
  switchMode('ondemand');
  $('topicInput').value=h.topic;
  showResultCards(h.agents);
  for(const r of(h.responses||[])){activateCard(r.agent);finalizeCard(r.agent,r.response)}
  if(h.summary)showSummary(h.summary);
  $('responseCount').textContent=`${h.responses?.length||0} / ${h.agents?.length||0} responses`;
  document.querySelectorAll('.history-item').forEach(el=>el.classList.remove('active'));
  currentRoundtable=null;
}
window._loadHistory=loadHistory;

// ── Scheduled Time ──
function calcNextScheduled(){
  const now=new Date();
  const target=new Date(now);
  target.setUTCHours(12,0,0,0);
  const day=target.getUTCDay();
  const daysUntilSunday=(7-day)%7;
  target.setUTCDate(target.getUTCDate()+(daysUntilSunday===0&&now>target?7:daysUntilSunday));
  const el=$('nextScheduled');
  if(el)el.textContent=target.toLocaleDateString('en-US',{weekday:'long',month:'short',day:'numeric'})+' at 8:00 PM WITA';
  const history=getHistory().filter(h=>h.id?.startsWith('sched_'));
  const area=$('scheduledHistory');
  if(area){
    area.innerHTML=history.length===0?'<div class="history-empty">No scheduled roundtables yet</div>':history.slice(0,5).map(h=>`<div class="history-item" onclick="window._loadHistory('${h.id}')"><div class="history-topic">${escHtml(h.topic)}</div><div class="history-meta"><span>${timeAgo(h.createdAt)}</span></div></div>`).join('');
  }
}
