// ── Deep Think API ──────────────────────────────────────
// Non-streaming Bedrock helper — collects full response as string
async function callBedrockSimple(prompt, agentId) {
  let result = ''
  for await (const chunk of streamAI(
    FORMAT_PROMPT,
    prompt,
    null,
    agentId || 'sarael'
  )) {
    result += chunk
  }
  return result
}

const DEEP_THINKS_FILE = join(__dirname, 'data', 'deep-thinks.json')

app.post('/api/deep-think', async (req) => {
  if (!requireAdmin(req)) return { ok: false, error: 'Admin required' }
  const { topic, agents } = req.body || {}
  if (!topic) return { ok: false, error: 'Topic required' }

  const debateAgents = agents || ['rafael', 'uriel', 'samael']

  // Phase 1: Each agent gives initial take (parallel)
  const initialResponses = await Promise.all(debateAgents.map(async (agentId) => {
    const soul = AGENTS[agentId]?.soul || ''
    const prompt = `${soul}\n\n${getSharedContext()}\n\nYou are in a DEEP THINK debate session. Topic: "${topic}"\n\nGive your initial analysis and position. Be specific, opinionated, and constructive. Consider risks, opportunities, and practical implementation. 300-500 words.`
    const response = await callBedrockSimple(prompt, agentId)
    return { agentId, phase: 'initial', response }
  }))

  // Phase 2: Each agent responds to others' takes (parallel)
  const debateResponses = await Promise.all(debateAgents.map(async (agentId) => {
    const soul = AGENTS[agentId]?.soul || ''
    const othersViews = initialResponses.filter(r => r.agentId !== agentId)
      .map(r => `**${AGENTS[r.agentId]?.name || r.agentId}** said: ${r.response}`).join('\n\n')
    const prompt = `${soul}\n\n${getSharedContext()}\n\nDEEP THINK debate continues. Topic: "${topic}"\n\nOther agents said:\n${othersViews}\n\nRespond to their points. Where do you agree? Where do you push back? What did they miss? Be direct. 200-400 words.`
    const response = await callBedrockSimple(prompt, agentId)
    return { agentId, phase: 'debate', response }
  }))

  // Phase 3: Synthesis
  const allContent = [...initialResponses, ...debateResponses]
    .map(r => `**${AGENTS[r.agentId]?.name || r.agentId}** (${r.phase}): ${r.response}`).join('\n\n---\n\n')
  const synthesisPrompt = `You are synthesizing a DEEP THINK debate session.\n\nTopic: "${topic}"\n\nAll agent contributions:\n${allContent}\n\nProduce a final synthesis:\n1. **Consensus Points** — what everyone agrees on\n2. **Key Debates** — where agents disagreed and the best resolution\n3. **Recommended Plan** — concrete action items with priorities\n4. **Risks & Mitigations** — top 3 risks identified\n5. **Open Questions** — what still needs to be decided\n\nBe specific and actionable. This will be turned into a visual plan.`
  const synthesis = await callBedrockSimple(synthesisPrompt, 'sarael')

  const result = {
    id: 'dt-' + Date.now(),
    topic,
    agents: debateAgents,
    phases: { initial: initialResponses, debate: debateResponses },
    synthesis,
    createdAt: Date.now()
  }

  // Store
  let data = { items: [] }
  try { data = JSON.parse(readFileSync(DEEP_THINKS_FILE, 'utf8')) } catch {}
  data.items.unshift(result)
  if (data.items.length > 20) data.items = data.items.slice(0, 20)
  writeFileSync(DEEP_THINKS_FILE, JSON.stringify(data, null, 2))

  trackEvent('deep_think', { id: result.id, topic: topic.slice(0, 80), agents: debateAgents })
  addNotification('Deep Think completed', topic.slice(0, 60), 'info', 'deep-think')
  return { ok: true, result }
})

app.get('/api/deep-think', async (req) => {
  try { return { ok: true, items: JSON.parse(readFileSync(DEEP_THINKS_FILE, 'utf8')).items } }
  catch { return { ok: true, items: [] } }
})

