app.post('/api/suggest-agent', async (req) => {
  const { message, context } = req.body || {}
  if (!message) return { ok: false, error: 'Message required' }

  const agentList = Object.entries(AGENTS).map(([id, a]) =>
    `${id}: ${a.name} — ${a.role || ''} — ${a.desc || ''}`
  ).join('\n')

  const prompt = `Given this message and context, which agent should handle this? Pick the BEST one.

Available agents:
${agentList}

User message: "${message}"
${context ? `Recent context: ${context}` : ''}

Reply with ONLY the agent ID (e.g., "rafael", "uriel", "azrael"). Nothing else. No quotes, no explanation.`

  try {
    const raw = await callBedrockSimple(prompt, 'sarael')
    // Extract just the agent ID from the response
    const cleaned = raw.trim().toLowerCase().replace(/[^a-z]/g, '')
    const agentId = AGENTS[cleaned] ? cleaned : 'michael'
    const agent = AGENTS[agentId]
    return { ok: true, agentId, agentName: agent?.name || agentId }
  } catch (err) {
    return { ok: false, error: 'Suggestion failed: ' + err.message }
  }
})

